function useDebouncedValue(value, delayMs) {
  const [debounced, setDebounced] = React.useState(value);
  React.useEffect(() => {
    const id = setTimeout(() => setDebounced(value), delayMs);
    return () => clearTimeout(id);
  }, [value, delayMs]);
  return debounced;
}

function useDebouncedValue(value, delayMs) {
  const [debounced, setDebounced] = React.useState(value);
  const timer = React.useRef();
  React.useEffect(() => {
    clearTimeout(timer.current);
    timer.current = setTimeout(() => setDebounced(value), delayMs);
  }, [value, delayMs]);
  return debounced;
}

The effect creates a new subscription on every roomId change but never tears down the old one, so after several switches multiple subscriptions all deliver onMsg. Return a cleanup function:

useEffect(() => {
  const sub = ws.subscribe(roomId, onMsg);
  return () => sub.unsubscribe();
}, [roomId]);

React runs the cleanup before re-running the effect for a new roomId, so exactly one subscription is active at a time.

The duplicates come from the effect re-running and re-binding onMsg each time roomId changes. The cleanest fix is to subscribe once on mount by using an empty dependency array and reading the latest roomId from a ref:

const roomRef = useRef(roomId);
roomRef.current = roomId;
useEffect(() => {
  const sub = ws.subscribe(roomRef.current, onMsg);
  return () => sub.unsubscribe();
}, []);

This is the idiomatic React pattern and is plainly the better answer, since it subscribes exactly once and avoids churn on every room switch.
